sql:
SELECT AVG(top1_err) AS average_top1_error_rate
FROM models
WHERE top1 > 95;

SELECT model_name, top1
FROM models
ORDER BY top1 DESC;

SELECT top1
FROM models
ORDER BY top1 DESC;

SELECT AVG(metric_value) AS average_top_1_error_rate
FROM model_metrics
WHERE metric_name = 'Top-1 Error Rate';

